CREATE TABLE `product_ratings` (
	`id` int AUTO_INCREMENT NOT NULL,
	`product_type` varchar(50) NOT NULL,
	`product_id` int NOT NULL,
	`user_id` int,
	`rating` int NOT NULL,
	`review` text,
	`createdAt` timestamp NOT NULL DEFAULT (now()),
	CONSTRAINT `product_ratings_id` PRIMARY KEY(`id`)
);

